1	<!DOCTYPE html>
2	<html lang="ja">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=1920, height=1080">
6	<title>学マス配信オーバーレイ</title>
7	<style>
8	/* =====================================================================
9	   学園アイドルマスター 配信オーバーレイ  (Twitch / マルチコメントビューア向け)
10	   - OBSのブラウザソースに 幅1920 / 高さ1080 で追加してください
11	   - 中央の縦長エリアはゲーム画面用に「窓」として空けてあります
12	   - 設定は下の :root 変数と、<script>冒頭の CONFIG で変更できます
13	   - キー操作:  G=配置ガイド表示 / D=デモON-OFF / C=設定パネル
14	   ===================================================================== */
15	
16	:root{
17	  /* ---- テーマカラー（Twitch寄せ＋アイドルパステル） ---- */
18	  --tw-purple:   #9146ff;
19	  --tw-purple-d: #6441a5;
20	  --accent-pink: #ff8fc7;
21	  --accent-aqua: #7fe3ff;
22	  --accent-cream:#fff4e6;
23	  --ink:         #3a2b4a;
24	  --panel-bg:    rgba(255,255,255,0.86);
25	  --panel-glass: rgba(86,46,130,0.55);
26	
27	  /* ---- 中央ゲーム窓のサイズ・位置（OBSでゲーム画面をここに合わせる） ---- */
28	  /* ゲーム画面(縦持ち)の幅。スマホ縦＝約 9:19.5 を想定 */
29	  --game-w: 560px;
30	  --game-h: 1010px;
31	  --game-top: 35px;            /* 上端の余白 */
32	  /* 中央寄せなので左右パネル幅は自動計算 */
33	
34	  /* ---- 顔出しカメラ ---- */
35	  --cam-aspect: 16 / 9;        /* 縦横比。4:3にしたいなら  4 / 3 */
36	  --cam-w: 340px;              /* 枠の幅（小さくすると映りも小さく） */
37	}
38	
39	*{ box-sizing:border-box; margin:0; padding:0; }
40	html,body{
41	  width:1920px; height:1080px; overflow:hidden;
42	  font-family:"Rounded Mplus 1c","Hiragino Maru Gothic ProN","Yu Gothic UI","Segoe UI",sans-serif;
43	  background:transparent;            /* OBSで透過 */
44	  color:var(--ink);
45	  -webkit-font-smoothing:antialiased;
46	}
47	
48	/* ===== 全体ステージ ===== */
49	#stage{ position:absolute; inset:0; }
50	
51	/* 背景の淡いグラデ枠（任意・透過の上に薄く乗せる） */
52	#bg-frame{
53	  position:absolute; inset:0;
54	  background:
55	    radial-gradient(1200px 700px at 10% -10%, rgba(255,143,199,.20), transparent 60%),
56	    radial-gradient(1200px 700px at 100% 110%, rgba(127,227,255,.20), transparent 60%),
57	    linear-gradient(160deg, rgba(145,70,255,.10), rgba(255,255,255,0) 40%);
58	  pointer-events:none;
59	}
60	
61	/* 中央ゲーム窓の枠（飾り。中身は透過＝ここにゲーム映像が見える） */
62	#game-window{
63	  position:absolute;
64	  width:var(--game-w); height:var(--game-h);
65	  top:var(--game-top); left:50%; transform:translateX(-50%);
66	  border-radius:26px;
67	  box-shadow:
68	     0 0 0 4px rgba(255,255,255,.9),
69	     0 0 0 9px var(--tw-purple),
70	     0 18px 50px rgba(86,46,130,.45);
71	  pointer-events:none;
72	}
73	/* 窓の四隅リボン */
74	#game-window::before,#game-window::after{
75	  content:""; position:absolute; width:54px; height:54px;
76	  border:5px solid var(--accent-pink); border-radius:14px;
77	}
78	#game-window::before{ top:-10px; left:-10px; border-right:none; border-bottom:none; }
79	#game-window::after{ bottom:-10px; right:-10px; border-left:none; border-top:none; }
80	
81	/* 配置ガイド（Gキーで切替）— ゲーム窓に実映像を合わせる時に使う */
82	#game-window.guide{ background:rgba(145,70,255,.25); }
83	#game-window.guide::after{ content:"ここにゲーム画面を合わせる"; }
84	
85	/* ===== 左カラム：コメント欄 ===== */
86	#left{
87	  position:absolute; top:0; bottom:0; left:0;
88	  width:calc((100% - var(--game-w)) / 2 - 24px);
89	  margin:0 12px; padding:18px 14px;
90	  display:flex; flex-direction:column;
91	}
92	.panel{
93	  background:var(--panel-bg);
94	  border-radius:22px;
95	  box-shadow:0 10px 30px rgba(86,46,130,.25), inset 0 0 0 2px rgba(255,255,255,.7);
96	  backdrop-filter:blur(2px);
97	}
98	.panel-title{
99	  display:flex; align-items:center; gap:10px;
100	  font-weight:800; font-size:24px; color:#fff;
101	  padding:10px 18px; border-radius:18px 18px 0 0;
102	  background:linear-gradient(100deg,var(--tw-purple),var(--accent-pink));
103	  letter-spacing:.04em;
104	}
105	.panel-title .dot{ width:14px;height:14px;border-radius:50%;background:#fff; box-shadow:0 0 10px #fff; }
106	
107	#comment-panel{ flex:1; display:flex; flex-direction:column; overflow:hidden; }
108	#comment-list{
109	  flex:1; overflow:hidden; display:flex; flex-direction:column;
110	  justify-content:flex-end; gap:10px; padding:16px 14px 18px;
111	}
112	.cmt{
113	  display:flex; gap:12px; align-items:flex-start;
114	  animation:cmtIn .45s cubic-bezier(.2,1.3,.4,1) both;
115	}
116	@keyframes cmtIn{ from{opacity:0; transform:translateY(18px) scale(.96);} to{opacity:1; transform:none;} }
117	.cmt .av{
118	  flex:0 0 auto; width:46px; height:46px; border-radius:50%;
119	  background:linear-gradient(135deg,var(--accent-aqua),var(--accent-pink));
120	  display:flex; align-items:center; justify-content:center;
121	  font-weight:800; color:#fff; font-size:20px; overflow:hidden;
122	  box-shadow:0 3px 8px rgba(0,0,0,.15);
123	}
124	.cmt .av img{ width:100%; height:100%; object-fit:cover; }
125	.cmt .body{ min-width:0; }
126	.cmt .name{ font-size:16px; font-weight:800; color:var(--tw-purple-d); display:flex; align-items:center; gap:6px; }
127	.cmt .badge{ font-size:11px; font-weight:800; color:#fff; background:var(--tw-purple); padding:1px 7px; border-radius:8px; }
128	.cmt .badge.mod{ background:#2ec27e; }
129	.cmt .badge.sub{ background:var(--accent-pink); }
130	.cmt .text{
131	  font-size:22px; font-weight:600; line-height:1.35; color:var(--ink);
132	  word-break:break-word; margin-top:1px;
133	}
134	/* スパチャ/ビッツ風の強調コメント */
135	.cmt.hl{ background:linear-gradient(100deg, #fff7d6, #ffe1ef); border-radius:16px; padding:8px 12px; box-shadow:0 6px 16px rgba(255,143,199,.35); }
136	.cmt.hl .amount{ font-size:14px; font-weight:900; color:#c1126b; }
137	
138	/* ===== 右カラム：配信情報 ===== */
139	#right{
140	  position:absolute; top:0; bottom:0; right:0;
141	  width:calc((100% - var(--game-w)) / 2 - 24px);
142	  margin:0 12px; padding:18px 14px;
143	  display:flex; flex-direction:column; gap:16px;
144	}
145	
146	/* 配信者ヘッダー */
147	#streamer{ padding:16px; display:flex; gap:14px; align-items:center; }
148	#streamer .icon{
149	  width:74px; height:74px; border-radius:22px; flex:0 0 auto;
150	  background:linear-gradient(135deg,var(--tw-purple),var(--accent-pink));
151	  display:flex; align-items:center; justify-content:center; color:#fff; font-size:36px; font-weight:900;
152	  box-shadow:0 6px 16px rgba(86,46,130,.35);
153	}
154	#streamer .who .nm{ font-size:28px; font-weight:900; color:var(--ink); }
155	#streamer .who .tg{ font-size:15px; font-weight:700; color:var(--tw-purple); }
156	#live-pill{
157	  margin-left:auto; align-self:flex-start;
158	  background:#eb0400; color:#fff; font-weight:900; font-size:14px;
159	  padding:4px 12px; border-radius:999px; letter-spacing:.1em;
160	  box-shadow:0 0 0 0 rgba(235,4,0,.6); animation:pulse 2s infinite;
161	}
162	@keyframes pulse{ 0%{box-shadow:0 0 0 0 rgba(235,4,0,.6);} 70%{box-shadow:0 0 0 14px rgba(235,4,0,0);} 100%{box-shadow:0 0 0 0 rgba(235,4,0,0);} }
163	
164	/* 今プレイ中カード */
165	#nowplay{ padding:14px 16px; }
166	#nowplay .lbl{ font-size:13px; font-weight:800; color:var(--accent-pink); letter-spacing:.1em; }
167	#nowplay .ttl{ font-size:24px; font-weight:900; color:var(--ink); margin-top:2px; line-height:1.2; }
168	#nowplay .sub{ font-size:15px; font-weight:700; color:#7a6b8a; margin-top:4px; }
169	
170	/* 時計＆配信経過 */
171	#info-row{ display:flex; gap:14px; }
172	.stat{ flex:1; padding:12px 14px; text-align:center; }
173	.stat .k{ font-size:13px; font-weight:800; color:var(--tw-purple); }
174	.stat .v{ font-size:30px; font-weight:900; color:var(--ink); font-variant-numeric:tabular-nums; }
175	
176	/* 目標バー */
177	#goal{ padding:14px 16px; }
178	#goal .row{ display:flex; justify-content:space-between; font-size:15px; font-weight:800; color:var(--ink); }
179	#goal .bar{ margin-top:8px; height:18px; border-radius:999px; background:rgba(145,70,255,.15); overflow:hidden; }
180	#goal .fill{ height:100%; width:62%; border-radius:999px; background:linear-gradient(90deg,var(--tw-purple),var(--accent-pink)); transition:width .6s ease; }
181	
182	/* 最近のイベント（フォロー/サブスク） ticker */
183	#events{ flex:1; display:flex; flex-direction:column; overflow:hidden; }
184	#event-list{ flex:1; overflow:hidden; display:flex; flex-direction:column; gap:8px; padding:12px 14px; }
185	.ev{ display:flex; align-items:center; gap:10px; font-size:17px; font-weight:800; color:var(--ink);
186	     animation:cmtIn .5s both; }
187	.ev .ic{ width:30px;height:30px;border-radius:50%; display:flex;align-items:center;justify-content:center; color:#fff; font-size:16px; }
188	.ev.follow .ic{ background:var(--accent-aqua); }
189	.ev.sub .ic{ background:var(--accent-pink); }
190	.ev.cheer .ic{ background:var(--tw-purple); }
191	.ev .nm{ color:var(--tw-purple-d); }
192	
193	/* 顔出し枠（カメラはこの枠の中にOBSで合わせる） */
194	/* 下段：SNS/コマンド ＋ 顔出し を横並び */
195	#bottom-row{ flex:0 0 auto; display:flex; gap:14px; align-items:stretch; }
196	#sns-cmd{ flex:1 1 auto; min-width:0; display:flex; flex-direction:column; overflow:hidden; }
197	#sns-cmd .sc-body{ flex:1; padding:12px 14px; display:flex; flex-direction:column; gap:10px; }
198	#sns-cmd .row{ display:flex; align-items:center; gap:8px; font-size:17px; font-weight:800; color:var(--ink); }
199	#sns-cmd .bdg{ font-size:12px; font-weight:900; color:#fff; padding:3px 9px; border-radius:999px; flex:0 0 auto; }
200	#sns-cmd .bdg.tw{ background:var(--tw-purple); } #sns-cmd .bdg.x{ background:#111; }
201	#sns-cmd .sc-sep{ height:2px; background:rgba(145,70,255,.18); border-radius:2px; margin:2px 0; }
202	#sns-cmd .sc-cmd{ display:flex; flex-wrap:wrap; gap:6px; }
203	#sns-cmd .cmd{ font-size:14px; font-weight:800; color:var(--tw-purple-d);
204	  background:rgba(145,70,255,.12); padding:3px 9px; border-radius:8px; }
205	
206	#facecam{ flex:0 0 auto; width:var(--cam-w); display:flex; flex-direction:column;
207	  border-radius:22px; overflow:hidden; position:relative;
208	  box-shadow:0 10px 30px rgba(86,46,130,.30); }
209	#facecam .cap{ display:flex; align-items:center; gap:10px;
210	  font-weight:800; font-size:20px; color:#fff; padding:9px 16px;
211	  background:linear-gradient(100deg,var(--tw-purple),var(--accent-pink)); }
212	#facecam .cap .cam{ width:26px;height:26px;border-radius:8px; background:rgba(255,255,255,.25);
213	  display:flex;align-items:center;justify-content:center; font-size:15px; }
214	#facecam .cap .live{ margin-left:auto; font-size:12px; font-weight:900; color:#fff;
215	  background:#eb0400; padding:3px 10px; border-radius:999px; letter-spacing:.08em; }
216	/* カメラ映像エリア（透過。OBSのカメラをここに重ねる）。カメラ比率に合わせる */
217	#facecam .view{ width:100%; aspect-ratio:var(--cam-aspect); position:relative; background:rgba(86,46,130,.06); }
218	#facecam .view::after{ content:""; position:absolute; inset:7px; border-radius:14px;
219	  box-shadow:0 0 0 3px var(--tw-purple), 0 0 0 6px rgba(255,255,255,.75); pointer-events:none; }
220	/* 四隅リボン */
221	#facecam .view i{ position:absolute; width:26px; height:26px; border:4px solid var(--accent-pink); z-index:2; }
222	#facecam .view i.tl{ top:2px; left:2px; border-right:none; border-bottom:none; border-radius:10px 0 0 0; }
223	#facecam .view i.tr{ top:2px; right:2px; border-left:none; border-bottom:none; border-radius:0 10px 0 0; }
224	#facecam .view i.bl{ bottom:2px; left:2px; border-right:none; border-top:none; border-radius:0 0 0 10px; }
225	#facecam .view i.br{ bottom:2px; right:2px; border-left:none; border-top:none; border-radius:0 0 10px 0; }
226	#facecam .view .hint{ position:absolute; inset:0; display:flex; align-items:center; justify-content:center;
227	  color:#b7a6cb; font-weight:800; font-size:16px; }
228	
229	/* 下部テロップ（任意メッセージ） */
230	#ticker{
231	  position:absolute; left:50%; bottom:14px; transform:translateX(-50%);
232	  width:var(--game-w); max-width:var(--game-w);
233	  background:var(--panel-glass); color:#fff; border-radius:16px;
234	  padding:8px 18px; font-size:18px; font-weight:800; text-align:center;
235	  box-shadow:0 8px 20px rgba(0,0,0,.25); backdrop-filter:blur(3px);
236	  overflow:hidden; white-space:nowrap;
237	}
238	#ticker .scroll{ display:inline-block; animation:scroll 18s linear infinite; }
239	@keyframes scroll{ from{transform:translateX(40%);} to{transform:translateX(-100%);} }
240	
241	/* 接続ステータス（左下小） */
242	#conn{
243	  position:absolute; left:14px; bottom:10px; font-size:12px; font-weight:800;
244	  padding:3px 10px; border-radius:999px; color:#fff; background:#888;
245	}
246	#conn.on{ background:#2ec27e; } #conn.demo{ background:var(--tw-purple); }
247	
248	/* 設定パネル（Cキー） */
249	#cfg{ position:absolute; top:14px; left:14px; z-index:50; display:none;
250	  background:#fff; color:#222; border-radius:14px; padding:14px 16px; width:360px;
251	  box-shadow:0 14px 40px rgba(0,0,0,.35); font-size:13px; }
252	#cfg.show{ display:block; }
253	#cfg h3{ font-size:15px; margin-bottom:8px; }
254	#cfg label{ display:block; margin:7px 0 2px; font-weight:700; }
255	#cfg input{ width:100%; padding:5px 8px; border:1px solid #ccc; border-radius:8px; }
256	#cfg .hint{ color:#888; margin-top:8px; line-height:1.5; }
257	</style>
258	</head>
259	<body>
260	<div id="stage">
261	  <div id="bg-frame"></div>
262	
263	  <!-- 中央：ゲーム画面用の窓（透過） -->
264	  <div id="game-window"></div>
265	
266	  <!-- 左：コメント -->
267	  <div id="left">
268	    <div id="comment-panel" class="panel">
269	      <div class="panel-title"><span class="dot"></span>コメント</div>
270	      <div id="comment-list"></div>
271	    </div>
272	  </div>
273	
274	  <!-- 右：情報 -->
275	  <div id="right">
276	    <div id="streamer" class="panel">
277	      <div class="icon" id="st-icon">P</div>
278	      <div class="who">
279	        <div class="nm" id="st-name">ウォール</div>
280	        <div class="tg" id="st-tag">@your_twitch</div>
281	      </div>
282	      <div id="live-pill">● LIVE</div>
283	    </div>
284	
285	    <div id="nowplay" class="panel">
286	      <div class="lbl">▶ NOW PLAYING</div>
287	      <div class="ttl" id="np-title">学園アイドルマスター</div>
288	      <div class="sub" id="np-sub">プロデュース配信 / 篠澤広がままならない</div>
289	    </div>
290	
291	    <div id="info-row">
292	      <div class="stat panel"><div class="k">時刻</div><div class="v" id="clock">--:--</div></div>
293	      <div class="stat panel"><div class="k">配信経過</div><div class="v" id="elapsed">0:00</div></div>
294	    </div>
295	
296	    <div id="goal" class="panel">
297	      <div class="row"><span id="goal-label">フォロワー目標</span><span id="goal-num">620 / 1000</span></div>
298	      <div class="bar"><div class="fill" id="goal-fill"></div></div>
299	    </div>
300	
301	    <div id="events" class="panel">
302	      <div class="panel-title"><span class="dot"></span>最近のフォロー / サブスク</div>
303	      <div id="event-list"></div>
304	    </div>
305	
306	    <!-- 下段：SNS/コマンド ＋ 顔出し枠 -->
307	    <div id="bottom-row">
308	      <div id="sns-cmd" class="panel">
309	        <div class="panel-title"><span class="dot"></span>SNS / コマンド</div>
310	        <div class="sc-body">
311	          <div class="row"><span class="bdg tw">Twitch</span><span id="sc-tw">your_twitch</span></div>
312	          <div class="row"><span class="bdg x">X</span><span id="sc-x">@your_x</span></div>
313	          <div class="sc-sep"></div>
314	          <div class="sc-cmd" id="sc-cmd"></div>
315	        </div>
316	      </div>
317	
318	      <!-- 顔出し枠：OBSのカメラ(映像キャプチャ)をこの枠の中に重ねて合わせる -->
319	      <div id="facecam">
320	        <div class="cap"><span class="cam">📷</span><span id="fc-name">ウォール</span><span class="live">● LIVE</span></div>
321	        <div class="view">
322	          <i class="tl"></i><i class="tr"></i><i class="bl"></i><i class="br"></i>
323	          <span class="hint"></span>
324	        </div>
325	      </div>
326	    </div>
327	  </div>
328	
329	  <!-- 下部テロップ -->
330	  <div id="ticker"><span class="scroll" id="ticker-text">学マス プロデュース配信中！　コメント・フォロー大歓迎です ✨　わからない所はコメントで教えてね</span></div>
331	
332	  <div id="conn" class="demo">DEMO</div>
333	
334	  <!-- 設定パネル -->
335	  <div id="cfg">
336	    <h3>⚙ オーバーレイ設定（Cで開閉）</h3>
337	    <label>配信者名</label><input id="i-name" value="ウォール">
338	    <label>Twitch ID（@）</label><input id="i-tag" value="@your_twitch">
339	    <label>下部テロップ</label><input id="i-ticker">
340	    <div class="hint">
341	      コメントは <b>わんコメ(OneComme)</b> を起動していれば自動表示されます。<br>
342	      （左下が「わんコメ接続OK」になれば連携成功）<br><br>
343	      G=ゲーム窓の配置ガイド / D=デモ切替 / C=この設定<br>
344	      連携手順は同梱の README をご覧ください。
345	    </div>
346	  </div>
347	</div>
348	
349	<!-- わんコメ(OneComme) 公式SDK。わんコメ起動中のみ読み込まれます（未起動なら自動でデモ表示） -->
350	<script src="http://localhost:11180/templates/preset/__origin/js/onesdk.js"></script>
351	
352	<script>
353	/* =====================================================================
354	   設定（ここを書き換えれば見た目が変わります）
355	   ===================================================================== */
356	const CONFIG = {
357	  streamerName: "ウォール",
358	  twitchTag:    "@wallx1",
359	  nowTitle:     "学園アイドルマスター",
360	  nowSub:       "プロデュース配信 / 目指せ一番星",
361	  tickerText:   "学マス プロデュース配信中！　コメント・フォロー大歓迎です ✨",
362	  goalLabel:    "フォロワー目標",
363	  goalCurrent:  120,
364	  goalTarget:   200,
365	  streamStart:  null,        // null=ページを開いた時刻を起点に経過表示
366	
367	  // ▼ SNS / コマンド一覧（顔出し枠の左に表示）
368	  xHandle:      "@wall_2525",                       // X(Twitter)
369	  //commands:     ["!discord", "!gakumas", "!fav"], // チャットコマンド（自由に変更）
370	
371	  // ▼ わんコメ(OneComme)連携
372	  //   true: わんコメが起動していればコメントを自動取得。起動していなければデモ表示
373	  //   false: 常にデモコメント
374	  useOneComme: true,
375	  onecommePort: 11180        // わんコメの待受ポート（通常はそのまま）
376	};
