401	const MAX_CMT = 12;
402	function pushComment(name, text, opt={}){
403	  const list = $("#comment-list");
404	  const el = document.createElement("div");
405	  el.className = "cmt" + (opt.highlight?" hl":"");
406	  const initial = (name||"?").trim()[0] || "?";
407	  const av = opt.icon ? `<img src="${opt.icon}" onerror="this.remove()">` : initial;
408	  const badges = (opt.badges||[]).map(b=>`<span class="badge ${b.cls||''}">${b.label}</span>`).join("");
409	  const amount = opt.amount ? `<span class="amount">${opt.amount}</span>` : "";
410	  el.innerHTML = `
411	    <div class="av">${av}</div>
412	    <div class="body">
413	      <div class="name">${escapeHtml(name)} ${badges} ${amount}</div>
414	      <div class="text">${escapeHtml(text)}</div>
415	    </div>`;
416	  list.appendChild(el);
417	  while(list.children.length > MAX_CMT) list.removeChild(list.firstChild);
418	}
419	function pushEvent(type, name, detail=""){
420	  const list = $("#event-list");
421	  const icon = {follow:"♥", sub:"★", cheer:"⚡"}[type] || "♥";
422	  const lbl  = {follow:"がフォローしました", sub:"がサブスク！", cheer:"が応援！"}[type] || "";
423	  const el = document.createElement("div");
424	  el.className = "ev "+type;
425	  el.innerHTML = `<div class="ic">${icon}</div><div><span class="nm">${escapeHtml(name)}</span> ${lbl} ${detail}</div>`;
426	  list.appendChild(el);
427	  while(list.children.length > 6) list.removeChild(list.firstChild);
428	}
429	function escapeHtml(s){ return String(s).replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
430	window.pushComment = pushComment;  // 外部から呼べるよう公開
