443	/* ---------- わんコメ(OneComme) 連携：公式 OneSDK 経由 ---------- */
444	function connectOneComme(){
445	  // SDKが読み込めていない＝わんコメ未起動 → デモにフォールバック
446	  if(typeof OneSDK === "undefined"){
447	    setConn("demo","DEMO (わんコメ未検出)");
448	    startDemo();
449	    return;
450	  }
451	  try{
452	    setConn("","わんコメ接続中…");
453	    OneSDK.setup({
454	      protocol: 'local',
455	      port: CONFIG.onecommePort,
456	      permissions: ['comments','connected']
457	    });
458	    OneSDK.ready().then(()=>{
459	      OneSDK.subscribe({
460	        action: 'comments',
461	        callback: (response)=>{
462	          // response は新着コメント配列。各要素の .data に中身が入る
463	          (response||[]).forEach(c=>{
464	            const d = c.data || {};
465	            const name = d.displayName || d.name || "名無し";
466	            const text = d.comment;
467	            if(text==null || text==="") return;
468	            const opt = { icon: d.profileImage };
469	            // Twitch等のバッジ・装飾（取得できる範囲で）
470	            const badges=[];
471	            if(d.isOwner)      badges.push({label:"配信者", cls:"mod"});
472	            if(d.isModerator)  badges.push({label:"MOD",   cls:"mod"});
473	            if(d.isSubscriber || d.isMember) badges.push({label:"サブスク", cls:"sub"});
474	            if(badges.length) opt.badges = badges;
475	            if(d.hasGift){ opt.highlight = true; }   // ギフト/Bits等は強調表示
476	            pushComment(name, text, opt);
477	          });
478	        }
479	      });
480	      OneSDK.connect();
481	      setConn("on","わんコメ接続OK");
482	    }).catch(()=>{ setConn("demo","DEMO (接続失敗)"); startDemo(); });
483	  }catch(err){
484	    setConn("demo","DEMO (初期化失敗)"); startDemo();
485	  }
486	}
487	function setConn(cls,label){ const c=$("#conn"); c.className=cls; c.textContent=label; }
