489	/* ---------- デモ（連携なしでも動く） ---------- */
490	const demoNames=["ぷろでゅーさー","saki_fan","はつぼし","kaede推し","ニワカP","ゆめ","しずく☆","ななくさ"];
491	const demoTexts=["かわいい〜！","評価A+いけるいける","そこは集中力上げた方がいいかも","初見です！","この衣装すき","がんばれー！","次のレッスン何にするの？","スキルカードの引き強すぎｗ","BGMいいよね","応援してます✨"];
492	let demoTimer=null;
493	function startDemo(){
494	  stopDemo();
495	  // 初期コメントを数件
496	  for(let i=0;i<4;i++) setTimeout(()=>randomComment(), i*300);
497	  demoTimer=setInterval(randomComment, 2600);
498	  // たまにフォロー/サブスク演出
499	  setInterval(()=>{ if(Math.random()<.5) pushEvent(Math.random()<.7?"follow":"sub", demoNames[Math.floor(Math.random()*demoNames.length)]); }, 7000);
500	}
501	function stopDemo(){ if(demoTimer){clearInterval(demoTimer); demoTimer=null;} }
502	function randomComment(){
503	  const n=demoNames[Math.floor(Math.random()*demoNames.length)];
504	  const t=demoTexts[Math.floor(Math.random()*demoTexts.length)];
505	  const r=Math.random();
506	  const opt={};
507	  if(r<.12){ opt.highlight=true; opt.amount="Cheer 500"; opt.badges=[{label:"サブスク",cls:"sub"}]; }
508	  else if(r<.2){ opt.badges=[{label:"MOD",cls:"mod"}]; }
509	  pushComment(n,t,opt);
510	}
